from math import gcd
from functools import reduce
from typing import List

class Solution:
    def minStable(self, nums: List[int], maxC: int) -> int:
        def hcf(arr):
            return reduce(gcd, arr)

        n = len(nums)
        max_stable = 0

        for i in range(n):
            for j in range(i, n):
                subarray = nums[i:j+1]
                if hcf(subarray) >= 2:
                    max_stable = max(max_stable, len(subarray))

        if max_stable == 0:
            return 0

        min_stable = max_stable

        for i in range(n):
            for j in range(i, n):
                subarray = nums[i:j+1]
                if hcf(subarray) >= 2:
                    for k in range(maxC + 1):
                        for modified_subarray in self.generate_modified_subarrays(subarray, k):
                            if hcf(modified_subarray) < 2:
                                min_stable = min(min_stable, len(modified_subarray))

        return min_stable if min_stable > 1 else 1

    def generate_modified_subarrays(self, subarray, max_modifications):
        if max_modifications == 0:
            yield subarray
        else:
            for i in range(len(subarray)):
                for new_value in range(2, 10**9 + 1):
                    modified_subarray = subarray[:i] + [new_value] + subarray[i+1:]
                    yield from self.generate_modified_subifications(modified_subarray, max_modifications - 1)

    def generate_modified_subifications(self, subarray, max_modifications):
        if max_modifications == 0:
